        "testProgram": doc["_id"],
        "count": doc["count"],
        "standard": ", ".join(standards) if standards else "N/A",
        "firstDate": doc.get("firstDate", "")[:10] if doc.get("firstDate") else "N/A",
        "lastDate": doc.get("lastDate", "")[:10] if doc.get("lastDate") else "N/A",
    })

df_summary = pd.DataFrame(rows).sort_values("count", ascending=False)

total = df_summary["count"].sum()
top10 = df_summary.head(10)

